export const MEETING_PLATFORMS=[{name:"Google Meet",match:e=>e.includes("meet.google.com")},{name:"Zoom",match:e=>e.includes("zoom.us/wc/")||e.includes("zoom.us/j/")},{name:"Microsoft Teams",match:e=>e.includes("teams.microsoft.com/l/meetup-join")||e.includes("teams.live.com/meet")}];export async function detectMeetingTab(){const e=await chrome.tabs.query({});for(const t of e)for(const e of MEETING_PLATFORMS)if(e.match(t.url||""))return{tab:t,platform:e.name};return null}export function detectQuestion(e){const t=e.trim().toLowerCase();return!(!t||t.split(" ").length<3)&&(!!t.endsWith("?")||["what","how","why","when","where","who","which","can","could","do","does","is","are"].some(e=>t.startsWith(e+" ")))}